insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'A can finish a work in 12 days and B in 18 days. Working together, how many days will they take?', 'A कोई work 12 days में और B 18 days में करता है। साथ में कितने days लगेंगे?', 'Combined rate = 1/12+1/18 = (30)/216. Time = 216/30 = 7.2 days. Therefore, answer = 7.2 days.', 'In work problems, rate is work per day. Workers together add rates, and total time is reciprocal of total rate. Final answer is 7.2 days.', 'Combined rate = 1/12+1/18 = (30)/216। Time = 216/30 = 7.2 days। अतः answer = 7.2 days।', 'Work problems में rate = work per day। साथ काम करने पर rates add होते हैं और time total rate का reciprocal होता है। Final answer 7.2 days है।', 'EASY', array['time-work','combined-work']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '7.2 days', '7.2 days', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15 days', '15 days', false, 'Averaged the individual times. Work rates add; times do not average.', 'Individual times का average लिया। Work rates add होते हैं, times नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '30 days', '30 days', false, 'Added the two times 12+18. Together they must take less time than either alone.', 'दोनों times add कर दिए। साथ काम करने पर time अकेले से कम होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '12 days', '12 days', false, 'Picked the faster worker''s time. Adding B''s rate reduces the time further.', 'Faster worker का time दे दिया। B की rate add होने से time और कम होगा।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'A can finish a work in 10 days and B in 15 days. Working together, how many days will they take?', 'A कोई work 10 days में और B 15 days में करता है। साथ में कितने days लगेंगे?', 'Combined rate = 1/10+1/15 = (25)/150. Time = 150/25 = 6 days. Therefore, answer = 6 days.', 'In work problems, rate is work per day. Workers together add rates, and total time is reciprocal of total rate. Final answer is 6 days.', 'Combined rate = 1/10+1/15 = (25)/150। Time = 150/25 = 6 days। अतः answer = 6 days।', 'Work problems में rate = work per day। साथ काम करने पर rates add होते हैं और time total rate का reciprocal होता है। Final answer 6 days है।', 'EASY', array['time-work','combined-work']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
