insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'A can finish a work in 20 days and B in 30 days. Working together, how many days will they take?', 'A कोई work 20 days में और B 30 days में करता है। साथ में कितने days लगेंगे?', 'Combined rate = 1/20+1/30 = (50)/600. Time = 600/50 = 12 days. Therefore, answer = 12 days.', 'In work problems, rate is work per day. Workers together add rates, and total time is reciprocal of total rate. Final answer is 12 days.', 'Combined rate = 1/20+1/30 = (50)/600। Time = 600/50 = 12 days। अतः answer = 12 days।', 'Work problems में rate = work per day। साथ काम करने पर rates add होते हैं और time total rate का reciprocal होता है। Final answer 12 days है।', 'EASY', array['time-work','combined-work']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
