insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'A can finish a work in 24 days and B in 36 days. Working together, how many days will they take?', 'A कोई work 24 days में और B 36 days में करता है। साथ में कितने days लगेंगे?', 'Combined rate = 1/24+1/36 = (60)/864. Time = 864/60 = 14.4 days. Therefore, answer = 14.4 days.', 'In work problems, rate is work per day. Workers together add rates, and total time is reciprocal of total rate. Final answer is 14.4 days.', 'Combined rate = 1/24+1/36 = (60)/864। Time = 864/60 = 14.4 days। अतः answer = 14.4 days।', 'Work problems में rate = work per day। साथ काम करने पर rates add होते हैं और time total rate का reciprocal होता है। Final answer 14.4 days है।', 'EASY', array['time-work','combined-work']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
