insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'A can finish a work in 30 days and B in 45 days. Working together, how many days will they take?', 'A कोई work 30 days में और B 45 days में करता है। साथ में कितने days लगेंगे?', 'Combined rate = 1/30+1/45 = (75)/1350. Time = 1350/75 = 18 days. Therefore, answer = 18 days.', 'In work problems, rate is work per day. Workers together add rates, and total time is reciprocal of total rate. Final answer is 18 days.', 'Combined rate = 1/30+1/45 = (75)/1350। Time = 1350/75 = 18 days। अतः answer = 18 days।', 'Work problems में rate = work per day। साथ काम करने पर rates add होते हैं और time total rate का reciprocal होता है। Final answer 18 days है।', 'EASY', array['time-work','combined-work']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
