insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'A can finish a work in 12 days. What fraction of work is done by A in 3 days?', 'A कोई work 12 days में करता है। 3 days में कितना fraction work होगा?', 'One-day work = 1/12. In 3 days, work = 3×1/12 = 3/12. Therefore, answer = 3/12.', 'If total work is 1 unit, a worker completing it in a days does 1/a per day. Multiplying by days worked gives completed fraction. Final answer is 3/12.', 'One-day work = 1/12। 3 days में work = 3×1/12 = 3/12। अतः answer = 3/12।', 'Total work को 1 unit मानें। 12 days में complete करने वाला worker रोज 1/12 करता है। Final answer 3/12 है।', 'MEDIUM', array['time-work','work-fraction']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
