insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '9/12', '9/12', false, 'Reported remaining work instead of completed work.', 'Completed work की जगह remaining work दिया।');
