insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'A and B can finish a work in 10 and 15 days respectively. They earn ₹2500 together. Find A''s share.', 'A और B work को क्रमशः 10 और 15 days में करते हैं। कुल wage ₹2500 है। A का share ज्ञात कीजिए।', 'Work-rate ratio A:B = 1/10:1/15 = 15:10. A''s share = 2500×15/(10+15) = 1500. Therefore, answer = ₹1500.', 'Payment follows contribution. Contribution per day is work rate, so the faster worker has the larger share. Final answer is ₹1500.', 'Work-rate ratio A:B = 1/10:1/15 = 15:10। A share = 2500×15/(10+15) = 1500। अतः answer = ₹1500।', 'Payment contribution के हिसाब से होता है। Contribution per day work rate है, इसलिए faster worker का share ज़्यादा होता है। Final answer ₹1500 है।', 'HARD', array['time-work','wages']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
