insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'Pipe A fills a tank in 6 hours and pipe B empties it in 12 hours. If both are opened, when will the tank fill?', 'Pipe A tank को 6 hours में भरता है और pipe B 12 hours में खाली करता है। दोनों open हों तो tank कब भरेगा?', 'Net rate = 1/6 - 1/12 = (6)/72. Time = 72/6 = 12 hours. Therefore, answer = 12 hours.', 'When one pipe empties, its rate opposes the filling pipe. Net work rate is the difference of rates. Final answer is 12 hours.', 'Net rate = 1/6 - 1/12 = (6)/72। Time = 72/6 = 12 hours। अतः answer = 12 hours।', 'Emptying pipe filling pipe के opposite काम करता है। Net work rate rates का difference है। Final answer 12 hours है।', 'HARD', array['time-work','pipes-cisterns']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
